// HasRecipe applies the HasEdge predicate on the "recipe" edge.
func HasRecipe() predicate.RecipeNutrition {
	return predicate.RecipeNutrition(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, RecipeTable, RecipeColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRecipeWith applies the HasEdge predicate on the "recipe" edge with a given conditions (other predicates).
func HasRecipeWith(preds ...predicate.Recipe) predicate.RecipeNutrition {
	return predicate.RecipeNutrition(func(s *sql.Selector) {
		step := newRecipeStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RecipeNutrition) predicate.RecipeNutrition {
	return predicate.RecipeNutrition(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RecipeNutrition) predicate.RecipeNutrition {
	return predicate.RecipeNutrition(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RecipeNutrition) predicate.RecipeNutrition {
	return predicate.RecipeNutrition(sql.NotPredicates(p))
}
